-- ملء محتوى عنقود "الأسرة والمجتمع" (usrah-mujtama) — ستة تصنيفات فرعية
-- draft بالكامل: بناء الأسرة (bina-usrah)، تربية الأبناء والمراهقين
-- (tarbiyat-abna)، المشكلات الأسرية والإصلاح (mushkilat-usariyya)،
-- التكافل وحقوق الفئات (takaful-ijtimai)، العمل التطوعي (amal-tatawwui)،
-- حماية الأسرة رقميًا (himayat-usrah-raqmiyya). كل تصنيف يحصل على درس
-- واحد (lessons + lesson_sections + lesson_citations)، بأسلوب الدفعات
-- السابقة (body + examples). المصادر المعتمدة المسمّاة صراحة لكل درس،
-- تحقَّقت عبر WebSearch/WebFetch من نصها الرسمي مباشرة قبل الصياغة:
-- 1) بناء الأسرة: إسلام ويب - مركز الفتوى، فتوى رقم 124273 (كيف تختار
--    الزوجة الصالحة، 30-6-2009م).
-- 2) تربية الأبناء والمراهقين: إسلام ويب - مركز الفتوى، فتوى رقم
--    286906 (نصائح في تربية الأولاد، 25-2-2015م).
-- 3) المشكلات الأسرية والإصلاح: دار الإفتاء المصرية، فتوى رقم 4237
--    (من أحكام جلسات التحكيم، 9 أغسطس 2003م، أ.د/ أحمد الطيب).
-- 4) التكافل وحقوق الفئات: دار الإفتاء المصرية، مقال "التكافل
--    الاجتماعي في الإسلام" (قسم ديننا)، مع حديث صحيح البخاري في فضل
--    كفالة اليتيم تحقَّق عبر WebSearch مستقلاً.
-- 5) العمل التطوعي: دار الإفتاء المصرية، فتوى رقم 7360 (العمل
--    التطوعي وفضله، 10 يناير 2023م، أ.د/ شوقي إبراهيم علام).
-- 6) حماية الأسرة رقميًا: دار الإفتاء المصرية، مقال "المؤشر العالمي
--    للفتوى: القرارات العالمية الداعية لحظر وسائل التواصل على
--    الأطفال..." (7 يوليو 2026م)، مع حديث "كلكم راع" المتفق عليه
--    تحقَّق عبر فتوى دار الإفتاء رقم 6706 المرتبطة بموضوع مشابه
--    (واجب الأسرة في الحماية).
-- ست آيات تحقَّقت حرفياً محليًا من artifacts/majalis/public/data/quran
-- عبر numberInSurah: الروم 21 (المودة والرحمة)، التحريم 6 (قوا
-- أنفسكم وأهليكم نارًا)، النساء 35 (فابعثوا حكمًا)، النساء 36
-- (الإحسان لليتامى والمساكين)، البقرة 184 (فمن تطوع خيرًا)، الإسراء
-- 36 (إن السمع والبصر والفؤاد كل أولئك كان عنه مسئولاً). ستة أحاديث
-- استُشهد بها بعد تحقق WebSearch من نصها وتخريجها ودرجتها بدقة: حديث
-- أبي هريرة "تنكح المرأة لأربع" (متفق عليه، البخاري 5090 ومسلم
-- 1466)، حديث ابن عمرو بن العاص "مروا أبناءكم بالصلاة" (رواه أبو
-- داود 495 وأحمد، صححه ابن الملقن)، حديث أبي الدرداء "ألا أخبركم
-- بأفضل من درجة الصيام والصلاة والصدقة... صلاح ذات البين" (رواه أحمد
-- وأبو داود 4919 والترمذي 2509 وقال حسن صحيح، صححه الألباني)، حديث
-- سهل بن سعد "أنا وكافل اليتيم في الجنة هكذا" (رواه البخاري 6005)،
-- حديث أنس بن مالك "ما من مسلم يغرس غرسًا أو يزرع زرعًا" (متفق
-- عليه)، حديث ابن عمر "كلكم راع وكلكم مسؤول عن رعيته" (متفق عليه).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الستة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) بناء الأسرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='78764421-7fd1-4e76-b5ab-7deffaa5dd74' AND title='أسس اختيار شريك الحياة وبناء الأسرة على الدين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أسس اختيار شريك الحياة وبناء الأسرة على الدين', 'بيان الأسس الشرعية الصحيحة لاختيار الزوج والزوجة وأثر ذلك في بناء أسرة مستقرة كما جاء في فتوى إسلام ويب رقم 124273', '78764421-7fd1-4e76-b5ab-7deffaa5dd74', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الدين أساس الاختيار، والتوكل والمشاورة والاستخارة طريق الوصول إليه', 'بيّنت الفتوى أن بناء الأسرة المستقرة يبدأ من حسن اختيار شريك الحياة، وأن الأصل الشرعي في هذا الاختيار هو تقديم الدين والخلق على ما سواهما من مال أو جمال أو حسب، لأن صاحب الدين هو الذي يُرجى منه القيام بحقوق الزوجية وتربية الأبناء على وجهها الصحيح. وذكرت الفتوى أربع وسائل معينة على تحصيل هذا الاختيار الموفَّق: التوكل على الله والدعاء بأن ييسر شريكًا صالحًا، ونية العفاف والإحصان بالزواج، ومشاورة أهل الرأي والصلاح ممن لهم خبرة ونصح، ثم صلاة الاستخارة طلبًا للتوفيق فيما استأثر الله بعلمه من عواقب الأمور. فإذا اجتمعت هذه الوسائل مع تقديم صاحب الدين كان ذلك أقرب طريق إلى أسرة تقوم على المودة والثبات لا على الأهواء العارضة.', 1),
    (v_lesson, 'examples', 'آية المودة والرحمة وحديث تقديم ذات الدين', 'قال تعالى: ﴿وَمِنْ آيَاتِهِ أَنْ خَلَقَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَاجًا لِّتَسْكُنُوا إِلَيْهَا وَجَعَلَ بَيْنَكُم مَّوَدَّةً وَرَحْمَةً إِنَّ فِي ذَٰلِكَ لَآيَاتٍ لِّقَوْمٍ يَتَفَكَّرُونَ﴾ (الروم: 21)، وهي الأصل القرآني الذي يبيّن أن غاية الزواج سكن نفسي تقوم عليه مودة ورحمة، لا مجرد اجتماع عارض بين طرفين. وفي بيان الأساس الذي يُبنى عليه هذا السكن، عن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم قال: "تُنكح المرأة لأربع: لمالها، ولحسبها، ولجمالها، ولدينها، فاظفر بذات الدين تربت يداك" (متفق عليه، رواه البخاري 5090 ومسلم 1466). فهذا الحديث يرسي معيار الأولوية عند الاختيار: أن يُقدَّم الدين على ما سواه، لأنه الأصل الذي تُبنى عليه المودة والرحمة المذكورتان في الآية، لا الأسباب العارضة من مال أو جمال أو حسب.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'إسلام ويب - مركز الفتوى، فتوى رقم 124273: كيف تختار الزوجة الصالحة (30-6-2009م)', 1);
  END IF;

  -- 2) تربية الأبناء والمراهقين
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='39a754a3-f85c-454b-8af1-0f52d8491bc1' AND title='أسس تربية الأبناء: القدوة والتدرج في الأمر بالعبادة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أسس تربية الأبناء: القدوة والتدرج في الأمر بالعبادة', 'بيان أسس تربية الأبناء تربية إسلامية سليمة تقوم على القدوة والتدرج كما جاء في فتوى إسلام ويب رقم 286906', '39a754a3-f85c-454b-8af1-0f52d8491bc1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التربية مسؤولية واجبة تبدأ من الصغر وتتدرج في الأمر والتأديب', 'أكدت الفتوى أن تربية الأبناء وتأديبهم بآداب الشرع من آكد المهمات التي تجب على الوالدين، وأن التعليم في الصغر كالنقش في الحجر رسوخًا وثباتًا، فينبغي أن تبدأ التربية بالعقيدة الصحيحة والأحكام الشرعية والآداب الإسلامية من نعومة الأظفار. ومن أهم أسس هذه التربية القدوة الحسنة، فالوالدان قدوة عملية لأبنائهما في الصلاة والصدق والأمانة وحسن الخلق، والطفل يميل بفطرته إلى تقليد والديه في كل ما يراه منهما. ومن أسسها أيضًا التدرج في الأمر بالعبادة، فيُؤمر الصبي بالصلاة عند بلوغه سن التمييز رفقًا وتعليمًا، ثم يُؤدَّب عليها برفق متزايد كلما كبر، مع الحرص على انتقاء الصحبة الصالحة له ومنعه من مخالطة أهل الفساد.', 1),
    (v_lesson, 'examples', 'آية وقاية الأهل من النار وحديث الأمر بالصلاة لسبع', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا قُوا أَنفُسَكُمْ وَأَهْلِيكُمْ نَارًا وَقُودُهَا النَّاسُ وَالْحِجَارَةُ﴾ (التحريم: 6)، وهي الأصل القرآني الذي أوجب على الوالدين حماية أبنائهما بالتربية والتوجيه، فسّرها علي رضي الله عنه بقوله: "علموهم وأدبوهم"، فجعل التعليم والتأديب صورة عملية لهذه الوقاية. وفي بيان التدرج العملي في الأمر بالعبادة، عن عمرو بن شعيب عن أبيه عن جده رضي الله عنهم أن النبي صلى الله عليه وسلم قال: "مروا أبناءكم بالصلاة وهم أبناء سبع سنين، واضربوهم عليها وهم أبناء عشر سنين، وفرقوا بينهم في المضاجع" (رواه أبو داود 495 وأحمد، وصححه ابن الملقن). فهذا الحديث يبيّن منهجًا تربويًا متدرجًا لا يُحمَّل فيه الطفل فوق طاقته دفعة واحدة، بل يُربى بالأمر أولاً ثم بالتأديب الرفيق إذا تأخر الاستجابة بعد بلوغه سنًا أكبر.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'إسلام ويب - مركز الفتوى، فتوى رقم 286906: نصائح في تربية الأولاد (25-2-2015م)', 1);
  END IF;

  -- 3) المشكلات الأسرية والإصلاح
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ff37f13e-7c57-4491-96b3-fc7ce9b513a5' AND title='التحكيم والإصلاح بين الزوجين عند الشقاق') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التحكيم والإصلاح بين الزوجين عند الشقاق', 'بيان مشروعية التحكيم بين الزوجين عند اشتداد الخلاف وأركانه وضوابطه كما جاء في فتوى دار الإفتاء المصرية رقم 4237', 'ff37f13e-7c57-4491-96b3-fc7ce9b513a5', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التحكيم طريق شرعي للإصلاح قبل أن يفضي الخلاف إلى الفراق', 'بيّنت الفتوى أن التحكيم بين الزوجين مشروع بنص قرآني صريح إذا خيف الشقاق بينهما، وأن أركانه الأساسية وجود طرفي النزاع، ووجود محكَّمين بينهما، ووجود موضوع الخلاف نفسه. والغاية من هذا التحكيم الإصلاح لا الانحياز لأحد الطرفين، ولذلك ينبغي أن يكون الحكمان من أهل الصلاح والحياد ومعرفة أحوال الزوجين، أحدهما من أهله والآخر من أهلها، لأنهما أقرب إلى معرفة أسباب الخلاف وأدعى لقبول كلامهما من الطرفين. وأكدت الفتوى أن الحكم إذا صدر دون سماع أقوال الطرفين وتمكينهما من عرض حجتهما كان ذلك مبطلاً له شرعًا، وأنه متى توافرت أركان التحكيم ورضي الطرفان بحكم الحكمين لزمهما العمل به فيما اتفقا عليه من الإصلاح.', 1),
    (v_lesson, 'examples', 'آية بعث الحكمين وحديث فضل الإصلاح بين الناس', 'قال تعالى: ﴿وَإِنْ خِفْتُمْ شِقَاقَ بَيْنِهِمَا فَابْعَثُوا حَكَمًا مِّنْ أَهْلِهِ وَحَكَمًا مِّنْ أَهْلِهَا إِن يُرِيدَا إِصْلَاحًا يُوَفِّقِ اللَّهُ بَيْنَهُمَا﴾ (النساء: 35)، وهي الأصل القرآني الصريح في مشروعية التحكيم الأسري، وفيها وعد إلهي بالتوفيق بين الزوجين إذا صدقت نية الحكمين في الإصلاح. وفي بيان عظم منزلة هذا الإصلاح، عن أبي الدرداء رضي الله عنه أن النبي صلى الله عليه وسلم قال: "ألا أخبركم بأفضل من درجة الصيام والصلاة والصدقة؟ قالوا: بلى، قال: صلاح ذات البين، فإن فساد ذات البين هي الحالقة" (رواه أحمد وأبو داود 4919 والترمذي 2509 وقال حسن صحيح، وصححه الألباني). فهذا الحديث يبيّن أن السعي في الإصلاح بين الزوجين المتخاصمين من أفضل الأعمال عند الله، وأن ضده وهو استمرار الفساد بينهما مُهلك للألفة كما يُهلك الحلق الشعر.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 4237: من أحكام جلسات التحكيم (9 أغسطس 2003م، أ.د/ أحمد الطيب)', 1);
  END IF;

  -- 4) التكافل وحقوق الفئات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e3c8b137-1dd7-406e-97cc-b31b1896c0bb' AND title='التكافل الاجتماعي وحقوق اليتامى والمساكين وذوي القربى') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التكافل الاجتماعي وحقوق اليتامى والمساكين وذوي القربى', 'بيان أصول التكافل الاجتماعي في الإسلام والفئات المستحقة له كما جاء في مقال دار الإفتاء المصرية "التكافل الاجتماعي في الإسلام"', 'e3c8b137-1dd7-406e-97cc-b31b1896c0bb', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التكافل حق يشمل اليتيم والمسكين وذا القربى ولا يقتصر على المسلمين', 'بيّن مقال دار الإفتاء المصرية أن التكافل الاجتماعي أصل راسخ من أصول الإسلام، يوفر الحماية والرعاية والأمن النفسي لأفراد المجتمع، وأن دائرة المستحقين له تشمل ذوي القربى واليتامى والمساكين والأرامل وكبار السن وذوي الاحتياجات، بل لا يقتصر هذا التكافل على المسلمين فقط بل يمتد إلى بني الإنسان جميعًا احترامًا لكرامته التي كرّمه الله بها. وتتحقق موارد هذا التكافل عبر وسائل متعددة شرعها الإسلام كالزكاة والصدقة والوقف والهبة والوصية والميراث، وكلها وسائل تُعيد توزيع المال بما يكفل حق الفئات الأولى بالرعاية دون أن يكون ذلك منّة من الغني على الفقير بل حقًا شرعيًا مقررًا له.', 1),
    (v_lesson, 'examples', 'آية الإحسان إلى اليتامى والمساكين وحديث فضل كفالة اليتيم', 'قال تعالى: ﴿وَاعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَبِالْوَالِدَيْنِ إِحْسَانًا وَبِذِي الْقُرْبَىٰ وَالْيَتَامَىٰ وَالْمَسَاكِينِ وَالْجَارِ ذِي الْقُرْبَىٰ وَالْجَارِ الْجُنُبِ﴾ (النساء: 36)، وهي الآية الجامعة التي رتّبت حقوق التكافل بعد حق الله وحق الوالدين مباشرة، فجعلت الإحسان إلى اليتيم والمسكين وذي القربى قرين توحيد الله في الذكر. وفي بيان عظم أجر من يقوم بشأن اليتيم خاصة، عن سهل بن سعد الساعدي رضي الله عنه أن النبي صلى الله عليه وسلم قال: "أنا وكافل اليتيم في الجنة هكذا"، وأشار بالسبابة والوسطى وفرّج بينهما شيئًا (رواه البخاري 6005). فهذا الحديث يبيّن أن كفالة اليتيم بالقيام على تربيته ونفقته من أعظم صور التكافل التي رتّب عليها الشرع قرب صاحبها من النبي صلى الله عليه وسلم في الجنة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'website', 'دار الإفتاء المصرية، مقال "التكافل الاجتماعي في الإسلام" (قسم ديننا)، dar-alifta.org', 1);
  END IF;

  -- 5) العمل التطوعي
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='27eca127-220b-4380-91e4-a3ddb7fd0638' AND title='فضل العمل التطوعي والخيري في الإسلام') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فضل العمل التطوعي والخيري في الإسلام', 'بيان استحباب العمل التطوعي وفضله العظيم وضوابط ممارسته كما جاء في فتوى دار الإفتاء المصرية رقم 7360', '27eca127-220b-4380-91e4-a3ddb7fd0638', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التطوع خير مستحب ينتفع به الفرد والمجتمع في آن واحد', 'بيّنت الفتوى أن التطوع في الاصطلاح الشرعي هو ما يتبرع به الشخص من أعمال الخير من ذات نفسه مما لا يلزمه فرضه، وأن هذا العمل مستحب استحبابًا مؤكدًا له من الأجر والثواب الشأن الكبير، شريطة أن يتم في ضوء القوانين واللوائح المنظمة له وتحت إشراف الجهات المختصة حتى لا يفضي إلى فوضى أو ضرر يخالف مقصود التطوع نفسه. وأكدت الفتوى أن أثر العمل التطوعي لا يقتصر على المتطوع نفسه من حصول الأجر وتحقيق الذات وشغل وقت الفراغ فيما ينفع، بل يمتد إلى المجتمع بأسره فينمّي فيه روح التعاون والعمل الجماعي، ويجعله أكثر تماسكًا وثقة بين أفراده.', 1),
    (v_lesson, 'examples', 'آية فضل التطوع بالخير وحديث أجر الصدقة الجارية', 'قال تعالى: ﴿فَمَن تَطَوَّعَ خَيْرًا فَهُوَ خَيْرٌ لَّهُ﴾ (البقرة: 184)، وهي جزء من آية أحكام الصيام، وقد استُشهد بها على الأصل العام في فضل التطوع بالخير وأن الزيادة عليه خير لصاحبها ولو لم يكن واجبًا عليه. وفي بيان امتداد أجر العمل التطوعي واستمراره، عن أنس بن مالك رضي الله عنه أن النبي صلى الله عليه وسلم قال: "ما من مسلم يغرس غرسًا أو يزرع زرعًا فيأكل منه طير أو إنسان أو بهيمة إلا كان له به صدقة" (متفق عليه). فهذا الحديث يبيّن أن العمل النافع للناس يبقى أجره جاريًا لصاحبه ما دام النفع به قائمًا، وهو معنى قريب من روح العمل التطوعي الذي ينتفع به المجتمع بعد صاحبه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 7360: العمل التطوعي وفضله (10 يناير 2023م، أ.د/ شوقي إبراهيم علام)', 1);
  END IF;

  -- 6) حماية الأسرة رقميًا
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9f0bebc1-7fff-4187-836c-5df3b5189d9b' AND title='مسؤولية الأسرة في الرقابة والوعي الرقمي الوقائي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مسؤولية الأسرة في الرقابة والوعي الرقمي الوقائي', 'بيان مسؤولية الوالدين في متابعة أبنائهم رقميًا ووقايتهم من مخاطر الإنترنت كما جاء في نهج دار الإفتاء المصرية في بناء الوعي الرقمي الوقائي', '9f0bebc1-7fff-4187-836c-5df3b5189d9b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الوقاية قبل وقوع الضرر: بناء وعي رقمي لا مجرد منع', 'تبنّت دار الإفتاء المصرية نهجًا سمّته "الفتوى الرقمية الوقائية"، قوامه الانتقال من معالجة الأضرار الرقمية بعد وقوعها إلى بناء وعي رقمي لدى الأبناء يقيهم قبل حدوثها، مع دعم دور الأسرة في المتابعة والرقابة الواعية لا الرقابة القمعية المجردة. وأكدت أن حفظ النفس والعقل والأخلاق من المقاصد الكلية للشريعة الإسلامية، وأن هذا الحفظ في العصر الرقمي يستلزم من الوالدين متابعة ما يطّلع عليه أبناؤهم من محتوى، وتعليمهم التمييز بين النافع والضار فيما يستمعونه ويشاهدونه، لا مجرد فرض القيود التقنية دون تربية وتوجيه مصاحب لها. ودعت إلى برنامج أسري متكامل يجمع بين الرقابة التقنية والحوار المستمر مع الأبناء حول ما يواجهونه في العالم الرقمي.', 1),
    (v_lesson, 'examples', 'آية مسؤولية السمع والبصر وحديث الراعي المسؤول عن رعيته', 'قال تعالى: ﴿وَلَا تَقْفُ مَا لَيْسَ لَكَ بِهِ عِلْمٌ إِنَّ السَّمْعَ وَالْبَصَرَ وَالْفُؤَادَ كُلُّ أُولَٰئِكَ كَانَ عَنْهُ مَسْئُولًا﴾ (الإسراء: 36)، وفيها أصل عام في مساءلة الإنسان عما يسمعه ويبصره، وهو معنى يتأكد في العصر الرقمي حيث تتضاعف مصادر ما يصل إلى سمع الأبناء وبصرهم مما لا يُعلم صدقه أو أثره. وفي بيان مسؤولية الوالدين تحديدًا عن أبنائهما، عن ابن عمر رضي الله عنهما أن النبي صلى الله عليه وسلم قال: "كلكم راعٍ وكلكم مسؤول عن رعيته... والرجل راعٍ في أهله وهو مسؤول عن رعيته" (متفق عليه). فهذا الحديث هو الأصل الذي بنت عليه دار الإفتاء تأكيدها على أن متابعة الأبناء رقميًا ليست خيارًا بل مسؤولية راعٍ عن رعيته يُسأل عنها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'website', 'دار الإفتاء المصرية، مقال "المؤشر العالمي للفتوى: القرارات العالمية الداعية لحظر وسائل التواصل على الأطفال تؤكد صواب نهج دار الإفتاء في بناء الوعي الرقمي الوقائي" (7 يوليو 2026م)، dar-alifta.org', 1);
  END IF;

